  1→//! Canonical runtime ports for Agent OS integrations.
  2→//!
  3→//! These traits define the only allowed runtime boundary between the kernel
  4→//! engine and external implementations (event stores, model providers, tool
  5→//! harnesses, policy engines, approval systems, and memory backends).
  6→//!
  7→//! Object-safety note:
  8→//! - Traits use `async-trait` for async dyn-dispatch.
  9→//! - Streaming uses boxed trait objects (`EventRecordStream`).
 10→
 11→use crate::error::KernelResult;
 12→use crate::event::{EventRecord, TokenUsage};
 13→use crate::ids::{ApprovalId, BranchId, RunId, SessionId, ToolRunId};
 14→use crate::policy::Capability;
 15→use crate::tool::{ToolCall, ToolOutcome};
 16→use async_trait::async_trait;
 17→use chrono::{DateTime, Utc};
 18→use futures_util::stream::BoxStream;
 19→use serde::{Deserialize, Serialize};
 20→
 21→pub type EventRecordStream = BoxStream<'static, KernelResult<EventRecord>>;
 22→
 23→#[derive(Debug, Clone, Serialize, Deserialize)]
 24→pub struct ModelCompletionRequest {
 25→    pub session_id: SessionId,
 26→    pub branch_id: BranchId,
 27→    pub run_id: RunId,
 28→    pub step_index: u32,
 29→    pub objective: String,
 30→    #[serde(default, skip_serializing_if = "Option::is_none")]
 31→    pub proposed_tool: Option<ToolCall>,
 32→}
 33→
 34→#[derive(Debug, Clone, Serialize, Deserialize)]
 35→#[serde(tag = "type", rename_all = "snake_case")]
 36→pub enum ModelDirective {
 37→    TextDelta {
 38→        delta: String,
 39→        #[serde(default, skip_serializing_if = "Option::is_none")]
 40→        index: Option<u32>,
 41→    },
 42→    Message {
 43→        role: String,
 44→        content: String,
 45→    },
 46→    ToolCall {
 47→        call: ToolCall,
 48→    },
 49→}
